import{_ as t,o,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"52. Overtime","description":"","frontmatter":{"title":"52. Overtime","eba":"Allied Health Professionals 2021-2026","topics":["hours","overtime","staffing","workload"]},"headers":[],"relativePath":"ebas/allied-health/hours-of-work/52-overtime.md","filePath":"ebas/allied-health/hours-of-work/52-overtime.md"}'),i={name:"ebas/allied-health/hours-of-work/52-overtime.md"};function n(s,e,l,h,p,m){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_52-overtime" tabindex="-1">52. Overtime <a class="header-anchor" href="#_52-overtime" aria-label="Permalink to &quot;52. Overtime&quot;">​</a></h1><p>This clause concerns overtime. Obligations regarding overtime are also contained in clause 90 (Workload Allocation and Safe Staffing).</p><p><strong>52.1</strong> General The Employer must not request or require an Employee to work overtime hours unless the overtime hours is reasonable.</p><p><strong>52.2</strong> Employee may refuse to work unreasonable overtime</p><p><strong>(a)</strong> An Employee may refuse to work overtime hours where they are unreasonable. In determining whether the overtime hours are reasonable or unreasonable, the following must be taken into account:</p><p><strong>(i)</strong> any risk to Employee health and safety from working the additional hours;</p><p><strong>(ii)</strong> the Employee’s personal circumstances, including family responsibilities;</p><p><strong>(iii)</strong> the needs of the workplace or enterprise in which the Employee is employed;</p><p><strong>(iv)</strong> whether the Employee is entitled to receive overtime payments, penalty rates or other compensation for, or a level of remuneration that reflects an expectation of, working additional hours;</p><p><strong>(v)</strong> any notice given by the Employer of any request or requirement to work the additional hours;</p><p><strong>(vi)</strong> any notice given by the Employee of their intention to refuse to work the additional hours;</p><p><strong>(vii)</strong> the usual patterns of work in the industry, or the part of an industry, in which the Employee works;</p><p><strong>(viii)</strong> the nature of the Employee’s role, and the Employee’s level of responsibility;</p><p><strong>(ix)</strong> how frequently an Employee is required to perform overtime; and</p><p><strong>(x)</strong> any other relevant matter; subject to subclause 52.2(b).</p><p><strong>(b)</strong> The relevance of the factors at subclause 52.2(a) and the weight to be given to each of them will vary according to the particular circumstances, namely:</p><p><strong>(i)</strong> in some cases it will require a balancing exercise between the factors;</p><p><strong>(ii)</strong> in some cases, a single factor will be of great importance and outweigh all others. One specific circumstance where this is the case is where an Employee’s personal circumstances (subclause 52.2(a)(ii)) require them to provide care for or look after a member of their immediate family or household during the time the Employer wants them to perform overtime. A request to perform overtime in this circumstance will be unreasonable and the Employee may refuse to work it.</p><p><strong>52.3</strong> Overtime - meaning Overtime, other than for casual Employees (see subclause 52.7), means work that is performed:</p><p><strong>(a)</strong> in excess of ordinary hours of work on any one shift;</p><p><strong>(b)</strong> in excess of the full-time ordinary hours described at <a href="/eba/ebas/allied-health/hours-of-work/47-hours-of-work.html">clause 47</a> (Hours of Work), save for the exception at <a href="/eba/ebas/allied-health/hours-of-work/56-daylight-savings.html">clause 56</a> relating to time worked during the daylight savings change over period; and/or</p><p><strong>(c)</strong> where a part-time Employee is directed to work additional hours but excluding an offer of additional ordinary hours as described at subclause 19.4 (Additional Ordinary Hours for Part Time Employees by Agreement only).</p><p><strong>52.4</strong> Overtime – Submitting Timesheets (or Equivalent) Where Required</p><p><strong>(a)</strong> Where required by the Employer, Employees will submit timesheets (or equivalent) with any overtime within the timeframe required by the Employer or, where that is not practicable, as soon as practicable.</p><p><strong>(b)</strong> Where overtime is worked but not submitted within the time required by subclause 52.4(a) and was not authorised in accordance with subclause 52.5(a) or (b), the Employee will be paid overtime subject to providing reasonable evidence of the hours worked to the Employer.</p><p><strong>(c)</strong> Where overtime is worked but not submitted within the time required at subclause 52.4(a) above, the Employer may seek an explanation and take reasonable steps to ensure an Employee is able to submit within the time required at subclause 52.4(a) above.</p><p><strong>52.5</strong> Meaning of ‘Authorised’</p><p><strong>(a)</strong> Overtime is authorised where:</p><p><strong>(i)</strong> the Employee is required or requested by the Employer (including the Employee’s manager or supervisor) to perform overtime;</p><p><strong>(ii)</strong> it is approved, usually in advance, either verbally or in writing by the Employer (including the Employee’s manager or supervisor);</p><p><strong>(iii)</strong> the Employer (including the Employee’s manager or supervisor) requires the Employee to complete allocated work that cannot reasonably be completed in ordinary time;</p><p><strong>(iv)</strong> the Employee has performed the overtime due to a demonstrable clinical need that could not have been met by some other means and authorisation could not reasonably have been obtained in advance; or</p><p><strong>(v)</strong> the Employee completes seeing a patient where this commenced during ordinary hours and continues beyond the Employee’s ordinary hours.</p><p><strong>(b)</strong> To ensure certainty as to when overtime is authorised, the Employer will develop and publish written protocols consistent with subclause 52.5 and <a href="/eba/ebas/allied-health/classification-staffing/90-workload-allocation-and-safe-staffing.html">clause 90</a> describing:</p><p><strong>(i)</strong> work that, because of its nature, is overtime authorised in advance if it cannot be completed within ordinary hours and is completed in overtime; and</p><p><strong>(ii)</strong> for matters that are not authorised in advance through a protocol or not authorised in accordance with subclause 52.5(a): A. how and from whom authorisation can be obtained; and / or B. when an Employee should not undertake the work.</p><p><strong>(c)</strong> Matters the protocols referred to at subclause 52.5(b) will address include but may not be limited to:</p><p><strong>(i)</strong> time spent completing work allocated to an Employee that cannot be completed during their ordinary hours being authorised overtime, except in the circumstances indicated in the protocols where the Employee should not complete the allocated work;</p><p><strong>(ii)</strong> non-patient/client facing work, including patient/client notes and administrative work;</p><p><strong>(iii)</strong> dealing with patients that other staff have not been able to deal with outside the Employee’s ordinary hours;</p><p><strong>(iv)</strong> mandatory reporting requirements; and</p><p><strong>(v)</strong> work required to be performed to comply with registration or professional association obligations.</p><p><strong>(d)</strong> Where overtime is worked it will be paid, including when it is not authorised:</p><p><strong>(i)</strong> under subclause 52.5(a); or</p><p><strong>(ii)</strong> in accordance with the protocols in subclause 52.5(b);</p><p>save that the Employer may take reasonable action to limit the need for future overtime by addressing the Employee&#39;s workload issues or through other appropriate measures including but not limited to steps required to satisfy clause 90 of this Agreement.</p><p><strong>(e)</strong> An Employer may create policies and /or procedures, consistent with the provisions of this Agreement, regarding the process the manager or supervisor is required to undertake prior to approving overtime. If a manager / supervisor approves an Employee’s overtime and it is inconsistent with the Employer’s polices / procedures, the Employee will still be paid for the overtime worked.</p><p><strong>52.6</strong> Payment of Authorised Overtime and Recall to Duty Authorised overtime and recall to duty for Employees, other than for casual Employees (see subclause 52.7), are to be paid at the rate of time and a half (150%) for the first two (2) hours and double time (200%) thereafter, save that authorised overtime and recall to duty:</p><p><strong>(a)</strong> outside the spread of twelve hours from the commencement of the last period of ordinary duty will be paid at the rate of double time (200%);</p><p><strong>(b)</strong> on a Saturday or Sunday will be paid at the rate of double time (200%);</p><p><strong>(c)</strong> on a public holiday will be paid at the rate of double time and a half (250%);</p><p><strong>(d)</strong> outside the spread of twelve hours from the commencement of work by an Employee rostered to work broken shifts will be paid at the rate of double time (200%). Only one penalty rate in this subclause 52.6 applies to a period of overtime or recall an Employee performs, that being the highest penalty rate that is applicable to that overtime or recall. See also subclause 47.8.</p><p><strong>52.7</strong> Casual Overtime</p><p><strong>(a)</strong> Overtime for casual Employees means work that is performed:</p><p><strong>(i)</strong> in excess of 10 hours on any one (1) shift; and/or</p><p><strong>(ii)</strong> in excess of 38 hours per week.</p><p><strong>(b)</strong> Authorised overtime for casual Employees is to be paid at the rate of time and seven eighths (187.5%) for the first two (2) hours and double time and a half (250%) thereafter, save that authorised overtime:</p><p><strong>(i)</strong> outside the spread of twelve hours from the commencement of the last period of ordinary duty will be paid at the rate of double time and a half (250%);</p><p><strong>(ii)</strong> on a Saturday or Sunday will be paid at the rate of double time and a half (250%);</p><p><strong>(iii)</strong> on a public holiday will be paid at the rate of triple time and one eighth (312.5%);</p><p><strong>(iv)</strong> outside the spread of twelve hours from the commencement of work by an Employee rostered to work broken shifts will be paid at the rate of double time and a half (250%). Only one penalty rate in this subclause 52.7(b) applies to a period of overtime a casual Employee performs, that being the highest penalty rate that is applicable to that overtime. See also subclause 47.8.</p><p><strong>52.8</strong> Minimum payment in certain circumstances Note: Minimum payment for recall is dealt with in <a href="/eba/ebas/allied-health/hours-of-work/53-recall-return-to-workplace.html">clause 53</a>. Where an Employee performs overtime, including rostered overtime, on a day that they do not otherwise perform work, such an Employee will be paid by the Employer a minimum of three (3) hours’ pay at the applicable overtime rates.</p><p><strong>52.9</strong> Time in Lieu</p><p><strong>(a)</strong> An Employee may, with the consent of the Employer which the Employer will not unreasonably withhold, elect to take time off in lieu of payment for overtime worked (including where recalled to duty) for a period equivalent to the overtime worked, plus a period equivalent to the overtime penalty incurred or a combination of time off and payment to the same value.</p><p>Examples: 1. An Employee performs three (3) hours of overtime outside the spread of twelve hours from the commencement of their last period of ordinary duty on a Monday. Under the Agreement these three (3) hours would be paid at double time for a total payment of six (6) ordinary hours. With the consent of the Employer, the Employee elects to take six (6) hours of time off in lieu. 2. An Employee performs two (2) hours of overtime in excess of their ordinary hours of work on a Wednesday. Under the Agreement these two (2) hours would be paid at time and a half for a total payment of three (3) ordinary hours. The Employee may, with the consent of the Employer, elect to take two (2) hours of time off in lieu and receive payment for one (1) hour.</p><p><strong>(b)</strong> Time off in lieu of overtime will be taken at a time mutually agreed between the Employer and the Employee, provided the Employer will not unreasonably refuse to agree to a request by an Employee to take time off in lieu at a specific time and that the accrual of such time off will not extend beyond a 28 day period, unless otherwise agreed.</p><p><strong>(c)</strong> Where the time off in lieu of overtime is not taken within 28 days, the overtime worked will be paid in the next pay period, unless agreement has been reached under subclause 52.9(b).</p><p><strong>(d)</strong> The Employer will record time off in lieu arrangements.</p><p><strong>(e)</strong> If, on the termination of the Employee’s employment, time off for overtime worked by the Employee to which subclause 52.9 applies has not been taken, the</p><p>Employer must pay the Employee for the overtime at the overtime rate applicable to the overtime when worked.</p><p><strong>52.10</strong> Transport In the event of any Employee finishing any period of overtime at a time when reasonable means of transport are not available for the Employee to return to their place of residence the Employer will provide adequate transport free of cost to the Employee.</p><p><strong>52.11</strong> Rest Break during overtime An Employee working overtime (including recall) will take a paid rest break of 20 minutes after each four (4) hours of overtime worked if required to continue work after the break.</p><p><strong>52.12</strong> Trainee Supervision Notwithstanding anything contained in <a href="/eba/ebas/allied-health/classification-staffing/88-trainee-supervision.html">clause 88</a> (Trainee Supervision), but subject to section 62 of the Act, any trainee may, due to medical emergency, be required to work reasonable overtime or shift duty at the discretion of the Employer. Such overtime or shift duty will be subject to the rates and/or allowances provided elsewhere in the Agreement.</p><p>Plain language terms: OT, extra hours, double time.</p>',74)])])}const c=t(i,[["render",n]]);export{u as __pageData,c as default};
